import { Inject, Injectable, Logger } from '@nestjs/common';
import { Cron } from '@nestjs/schedule';
import {
  ISessionRepository,
  SESSION_REPOSITORY,
} from '../interfaces/session-repository.interface';

/** Sessions left ACTIVE beyond this are expired by the cron (README §2.3). */
const MAX_ACTIVE_AGE_MS = 2 * 60 * 60 * 1000; // 2 hours

/**
 * Cron cleanup of stale ACTIVE sessions (README §2.3 State Machine).
 * Runs every 5 minutes; marks ACTIVE sessions older than 2h as EXPIRED.
 */
@Injectable()
export class SessionExpirationService {
  private readonly logger = new Logger(SessionExpirationService.name);

  constructor(
    @Inject(SESSION_REPOSITORY)
    private readonly sessions: ISessionRepository,
  ) {}

  @Cron('*/5 * * * *')
  async expireStaleSessions(): Promise<void> {
    const threshold = new Date(Date.now() - MAX_ACTIVE_AGE_MS);
    const stale = await this.sessions.findActiveOlderThan(threshold);

    for (const session of stale) {
      session.expire(); // ACTIVE → EXPIRED (idempotent for COMPLETED)
      await this.sessions.save(session);
    }

    if (stale.length > 0) {
      this.logger.log(`Expired ${stale.length} stale ACTIVE session(s).`);
    }
  }
}
